-- 1.1)
SELECT COUNT(*) FROM indicados_ao_oscar;

-- 1.2.1)
SELECT DISTINCT categoria FROM indicados_ao_oscar ORDER BY categoria;

-- 1.2.2)
SELECT COUNT(DISTINCT categoria) FROM indicados_ao_oscar;

-- 1.3)
SELECT MIN(ano_cerimonia) FROM indicados_ao_oscar;

-- 1.4)
SELECT MAX(ano_cerimonia) FROM indicados_ao_oscar;

-- 1.5)
SELECT COUNT(DISTINCT ano_cerimonia) FROM indicados_ao_oscar;

-- 2.1)
SELECT categoria, COUNT(*) AS total FROM indicados_ao_oscar GROUP BY categoria ORDER BY total DESC;

-- 2.2)
SELECT categoria, COUNT(*) AS total FROM indicados_ao_oscar GROUP BY categoria ORDER BY total DESC LIMIT 1;

-- 2.3)
SELECT categoria, COUNT(*) AS total FROM indicados_ao_oscar GROUP BY categoria ORDER BY total ASC LIMIT 1;

-- 2.4)
SELECT MAX(ano_cerimonia) FROM indicados_ao_oscar WHERE categoria = 'ACTRESS';

-- 2.5)
SELECT DISTINCT categoria FROM indicados_ao_oscar WHERE ano_cerimonia = 1928 AND categoria NOT IN (SELECT DISTINCT categoria FROM indicados_ao_oscar WHERE ano_cerimonia = (SELECT MAX(ano_cerimonia) FROM indicados_ao_oscar));

-- 2.6)
SELECT DISTINCT categoria FROM indicados_ao_oscar WHERE categoria LIKE '%DIRECTING%';

-- 3.1)
SELECT COUNT(*) FROM indicados_ao_oscar WHERE nome_indicado LIKE '%Natalie Portman%';

-- 3.2)
SELECT COUNT(*) FROM indicados_ao_oscar WHERE nome_indicado LIKE '%Natalie Portman%' AND vencedor = true;

-- 3.3)
SELECT ano_cerimonia, nome_filme FROM indicados_ao_oscar WHERE nome_indicado LIKE '%Natalie Portman%' ORDER BY ano_cerimonia;

-- 3.4)
SELECT ano_cerimonia, categoria, nome_filme, vencedor FROM indicados_ao_oscar WHERE nome_indicado LIKE '%Natalie Portman%' ORDER BY ano_cerimonia;

-- 3.5)
SELECT COUNT(*) FROM indicados_ao_oscar WHERE nome_indicado LIKE '%Viola Davis%';

-- 3.6)
SELECT COUNT(*) FROM indicados_ao_oscar WHERE nome_indicado LIKE '%Viola Davis%' AND vencedor = true;

-- 3.7)
SELECT ano_cerimonica, nome_filme, categoria, vencedor FROM indicados_ao_oscar WHERE nome_indicado LIKE '%Viola Davis%' ORDER BY ano_cerimonia;

-- 3.8)
SELECT COUNT(*) FROM indicados_ao_oscar WHERE nome_indicado LIKE '%Amy Adams%' AND vencedor = true;

-- 3.9)
SELECT COUNT(*) FROM indicados_ao_oscar WHERE nome_indicado LIKE '%Amy Adams%' AND vencedor = false;

-- 3.10)
SELECT COUNT(*) FROM indicados_ao_oscar WHERE nome_indicado LIKE '%Denzel Washington%' AND vencedor = true;

-- 3.11)
SELECT COUNT(*) FROM indicados_ao_oscar WHERE nome_indicado LIKE '%Denzel Washington%';

-- 3.12)
SELECT ano_cerimonia, categoria, nome_filme FROM indicados_ao_oscar WHERE nome_indicado LIKE '%Denzel Washington%' AND vencedor = true ORDER BY ano_cerimonia;

-- 4.1)
SELECT nome_indicado, ano_cerimonia, nome_filme FROM indicados_ao_oscar WHERE categoria = 'ACTRESS' AND vencedor = true ORDER BY ano_cerimonia ASC LIMIT 1;

-- 4.2)
SELECT nome_indicado, ano_cerimonia, nome_filme FROM indicados_ao_oscar WHERE categoria = 'ACTOR' AND vencedor = true ORDER BY ano_cerimonia ASC LIMIT 1;

-- 4.3)
SELECT COUNT(*) FROM indicados_ao_oscar WHERE vencedor = true;

-- 4.4)
SELECT ano_cerimonia, nome_filme FROM indicados_ao_oscar WHERE categoria IN ('OUTSTANDING PICTURE', 'BEST PICTURE') AND vencedor = true ORDER BY ano_cerimonia;

-- 4.5)
SELECT COUNT(DISTINCT nome_filme) FROM indicados_ao_oscar WHERE vencedor = true;

-- 5.1)
SELECT nome_indicado, COUNT(*) AS total FROM indicados_ao_oscar GROUP BY nome_indicado HAVING total > 1 ORDER BY total DESC;

-- 5.2)
SELECT nome_indicado, COUNT(*) AS total FROM indicados_ao_oscar GROUP BY nome_indicado ORDER BY total DESC LIMIT 1;

-- 5.3)
SELECT nome_indicado, COUNT(*) AS total FROM indicados_ao_oscar GROUP BY nome_indicado HAVING total > 3 AND SUM(vencedor) = 0 ORDER BY total DESC;

-- 5.4)
SELECT nome_indicado, COUNT(DISTINCT categoria) AS categorias FROM indicados_ao_oscar GROUP BY nome_indicado HAVING categorias > 1 ORDER BY categorias DESC;

-- 5.5)
SELECT COUNT(*) FROM (SELECT nome_indicado FROM indicados_ao_oscar GROUP BY nome_indicado HAVING COUNT(*) = 1) AS sub;

-- 5.6)
SELECT ano_cerimonia, COUNT(*) AS total FROM indicados_ao_oscar GROUP BY ano_cerimonia ORDER BY total DESC LIMIT 1;

-- 6.1)
SELECT ano_cerimonia, nome_filme, categoria FROM indicados_ao_oscar WHERE nome_filme LIKE '%Toy Story%' AND vencedor = true ORDER BY ano_cerimonia;

-- 6.2)
SELECT COUNT(*) FROM indicados_ao_oscar WHERE nome_filme LIKE '%Toy Story%';

-- 6.3)
SELECT DISTINCT categoria FROM indicados_ao_oscar WHERE nome_filme LIKE '%Toy Story%';

-- 6.4)
SELECT DISTINCT edicao_cerimonia, ano_cerimonia FROM indicados_ao_oscar WHERE nome_filme LIKE '%Crash%';

-- 6.5)
SELECT COUNT(*) FROM indicados_ao_oscar WHERE nome_filme LIKE '%Crash%';

-- 6.6)
SELECT nome_filme, vencedor FROM indicados_ao_oscar WHERE nome_filme LIKE '%Crash%' AND categoria IN ('OUTSTANDING PICTURE', 'BEST PICTURE');

-- 6.7)
SELECT COUNT(*) FROM indicados_ao_oscar WHERE nome_filme LIKE '%Central do Brasil%' OR nome_filme LIKE '%Central Station%';

-- 6.8)
SELECT * FROM indicados_ao_oscar WHERE nome_filme LIKE '%Central do Brasil%' OR nome_filme LIKE '%Central Station%';